import{_ as t,o,c as a,a2 as s}from"./chunks/framework.BWuWLRhz.js";const h=JSON.parse('{"title":"RFC 0006 — Deployment & upgrade strategy","description":"","frontmatter":{},"headers":[],"relativePath":"rfcs/0006-deployment-upgrade-strategy.md","filePath":"rfcs/0006-deployment-upgrade-strategy.md"}'),r={name:"rfcs/0006-deployment-upgrade-strategy.md"};function n(i,e,d,l,c,p){return o(),a("div",null,[...e[0]||(e[0]=[s(`<h1 id="rfc-0006-—-deployment-upgrade-strategy" tabindex="-1">RFC 0006 — Deployment &amp; upgrade strategy <a class="header-anchor" href="#rfc-0006-—-deployment-upgrade-strategy" aria-label="Permalink to &quot;RFC 0006 — Deployment &amp; upgrade strategy&quot;">​</a></h1><p><strong>Status:</strong> Implemented<br><strong>Date:</strong> June 2026<br><strong>Author:</strong> kasunben<br><strong>Scope:</strong> Docker images + Compose, CI (Task 0.5.8), <code>packages/db</code> (migrations), <code>apps/auth</code>, <code>bin/sv</code>, <code>docs/self-hosting.md</code>, <code>docs/upgrade.md</code>, SRS §3.1 + NFRs<br><strong>Incorporated into plan:</strong> Yes — SRS §3.15 and <strong>Task 0.5.14</strong>. The implementation (pull-based images, graceful shutdown, drizzle-kit + expand-contract migrations, <code>sv backup</code>/<code>restore</code> + auto-snapshot, tag-pinned rollback) lands in that task; image publishing depends on the CI pipeline (Task 0.5.8).</p><hr><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>Define a <strong>tiered, low-downtime upgrade model</strong> for Sovereign&#39;s single-machine Docker Compose deployment (NFR-01):</p><ul><li><strong>Pull-based versioned images</strong> are the canonical upgrade unit — CI builds and tags runtime + auth images; operators <strong>pull then recreate</strong> (no host build).</li><li><strong>Cutover is tiered:</strong> <strong>graceful restart</strong> is the default (a few seconds, hidden by the reverse proxy); <strong>blue-green</strong> is an optional advanced path for true zero-downtime.</li><li><strong>Migrations</strong> move to <strong>drizzle-kit</strong> under an <strong>expand-contract</strong> discipline (backward-compatible within a release) so overlap and rollback are safe.</li><li><strong>Backups become first-class:</strong> <code>sv backup</code> / <code>sv restore</code> plus an <strong>automatic pre-upgrade snapshot</strong>, making <strong>tag-pinned rollback</strong> real.</li></ul><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># the target upgrade flow (pinned image, no host build)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$EDITOR .env                       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># bump SOVEREIGN_VERSION=0.7.0</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.prod.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pull</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">docker</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compose</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -f</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docker-compose.prod.yml</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> up</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # auto-snapshot → migrate → graceful recreate</span></span></code></pre></div><h2 id="motivation" tabindex="-1">Motivation <a class="header-anchor" href="#motivation" aria-label="Permalink to &quot;Motivation&quot;">​</a></h2><p>Sovereign is self-hosted and ships updates regularly, but has no smooth-upgrade story. The only documented path is <code>git pull &amp;&amp; docker compose up --build -d</code>, which:</p><ul><li><strong>builds on the host</strong> — downtime spans the build, not just a restart;</li><li><strong>drops in-flight requests</strong> — the standalone servers have no graceful shutdown, so a container recreate severs open connections;</li><li><strong>relies on idempotent bootstrap DDL</strong> (<code>CREATE TABLE IF NOT EXISTS</code>) — fine for additive columns/tables, but cannot express renames, drops, type changes, or backfills, and offers no applied-migration ledger;</li><li><strong>has no tooled backups</strong> — operators copy the data dir or run <code>pg_dump</code> by hand; and</li><li><strong>has no rollback story</strong> — reverting means git-revert + rebuild, with no guaranteed-good data snapshot to fall back to.</li></ul><p>NFR-10 already requires a documented upgrade path and NFR-04 the breaking-change discipline for published packages. This RFC operationalizes both for the <strong>deployment</strong> as a whole, and prepares the ground for breaking changes and DB migrations as the project moves toward and past v1.0.</p><h2 id="current-state-what-this-builds-on" tabindex="-1">Current state (what this builds on) <a class="header-anchor" href="#current-state-what-this-builds-on" aria-label="Permalink to &quot;Current state (what this builds on)&quot;">​</a></h2><ul><li><strong>Topology</strong> (<code>docs/self-hosting.md</code>, SRS §3.1): two long-running Node processes — runtime (only externally exposed) + auth (internal) — via Docker Compose, <code>restart: unless-stopped</code>, healthchecks on <code>/api/health</code>, <code>depends_on: service_healthy</code>. A reverse proxy (Caddy/nginx/Traefik) is assumed in front for TLS and routing.</li><li><strong>Standalone output:</strong> both apps run <code>node server.js</code> reading <code>PORT</code>/<code>HOSTNAME</code> (<code>runtime/next.config.ts</code>, <code>apps/auth/next.config.ts</code>); three-stage Dockerfiles build from Next.js standalone output; prod uses a <strong>named volume</strong> (<code>sovereign_data</code>) and a non-root runner.</li><li><strong>Health endpoints:</strong> <code>runtime/app/api/health/route.ts</code> (public liveness) and <code>runtime/app/api/admin/health/route.ts</code> (rich report — <code>platformVersion</code>, database dialect/size, auth reachability, uptime).</li><li><strong>Migration scaffolding, not yet load-bearing:</strong> <code>packages/db/src/migrate.ts</code> exposes a dialect-aware <code>runMigrations(pdb, folder)</code>, but evolution today is the idempotent <code>bootstrapPlatformDb()</code> in <code>packages/db/src/bootstrap.ts</code> (guarded against the Drizzle schema by <code>packages/db/src/schema/parity.test.ts</code>). The auth server runs better-auth&#39;s migrator + <code>ensureAuthTables()</code> on every startup (<code>apps/auth/src/migrate.ts</code>, <code>apps/auth/instrumentation.ts</code>).</li><li><strong>CLI:</strong> <code>bin/sv</code> (<code>citty</code> + <code>consola</code>) is a thin orchestrator delegating to scripts and <code>pnpm</code>/<code>turbo</code> — the natural home for <code>backup</code>/<code>restore</code>/<code>upgrade</code> (<code>bin/sv.ts</code>, pure logic in <code>bin/helpers.ts</code>).</li><li><strong>Versioning conventions</strong> (CLAUDE.md): the platform version (root <code>package.json</code>) tracks roadmap milestones; <code>@sovereignfs/sdk</code> and <code>@sovereignfs/ui</code> follow npm semver (NFR-04: patch never breaks); breaking changes get a migration note in <code>docs/upgrade.md</code>.</li><li><strong>No CI / no image registry yet</strong> — both are introduced by Task 0.5.8, on which this RFC&#39;s image-publishing piece depends.</li></ul><h2 id="proposed-design" tabindex="-1">Proposed design <a class="header-anchor" href="#proposed-design" aria-label="Permalink to &quot;Proposed design&quot;">​</a></h2><h3 id="_1-upgrade-unit-—-published-versioned-images" tabindex="-1">1. Upgrade unit — published versioned images <a class="header-anchor" href="#_1-upgrade-unit-—-published-versioned-images" aria-label="Permalink to &quot;1. Upgrade unit — published versioned images&quot;">​</a></h3><p>CI (Task 0.5.8) builds the <strong>runtime</strong> and <strong>auth</strong> images and pushes semver tags to a container registry (GHCR proposed):</p><ul><li><code>:MAJOR.MINOR.PATCH</code> (immutable, e.g. <code>:0.7.0</code>) — the pinning tag;</li><li><code>:MAJOR.MINOR</code> (e.g. <code>:0.7</code>) — latest patch in a minor line;</li><li><code>:stable</code> — the current recommended release.</li></ul><p><code>docker-compose.prod.yml</code> references <code>image:</code> tags pinned by an <code>.env</code> variable (<code>SOVEREIGN_VERSION</code>), so the upgrade is <strong>pull-based, not build-based</strong>:</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">services</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  runtime</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghcr.io/sovereignfs/sovereign-runtime:\${SOVEREIGN_VERSION}</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">  auth</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">    image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">ghcr.io/sovereignfs/sovereign-auth:\${SOVEREIGN_VERSION}</span></span></code></pre></div><p>Building from source (<code>up --build</code>) remains documented as a <strong>fallback</strong> for forks and air-gapped deployments. Pinning by immutable patch tag is what makes <strong>rollback</strong> a one-line repin (§5).</p><h3 id="_2-cutover-—-tiered" tabindex="-1">2. Cutover — tiered <a class="header-anchor" href="#_2-cutover-—-tiered" aria-label="Permalink to &quot;2. Cutover — tiered&quot;">​</a></h3><p><strong>Default — graceful restart.</strong> Add <code>SIGTERM</code>/<code>SIGINT</code> handlers to both standalone servers: stop accepting new connections, <strong>drain in-flight requests</strong> within a bounded grace period, close the DB pool, then exit. Combined with the existing healthcheck-gated recreate and the reverse proxy&#39;s connect-retry, the swap is a brief gap (seconds) rather than a burst of 502s. Compose sets a matching <code>stop_grace_period</code>.</p><p><strong>Advanced — blue-green.</strong> For operators who need no gap: run a second stack (&quot;green&quot;) on alternate internal ports against the same data volume, health-check it, <strong>flip the reverse-proxy upstream</strong> from blue to green, then retire blue. Documented as an opt-in procedure (proxy snippets for Caddy/nginx/Traefik). Blue-green <strong>requires</strong> expand-contract migrations (§3) because both versions serve against one database during the overlap.</p><p>Multi-node rolling / orchestrators (k8s) are explicitly <strong>out of scope</strong> — they conflict with the single-machine model (NFR-01).</p><h3 id="_3-database-migrations-—-drizzle-kit-expand-contract" tabindex="-1">3. Database migrations — drizzle-kit + expand-contract <a class="header-anchor" href="#_3-database-migrations-—-drizzle-kit-expand-contract" aria-label="Permalink to &quot;3. Database migrations — drizzle-kit + expand-contract&quot;">​</a></h3><p><strong>Tooling.</strong> Introduce <code>drizzle.config.*</code> and generated SQL migrations under <code>packages/db/migrations/</code>, and promote <code>runMigrations()</code> to load-bearing:</p><ul><li>Migrations run as a <strong>one-shot step gated by <code>depends_on</code></strong> (a short-lived <code>migrate</code> service the app services wait on) — or, equivalently, a startup hook — holding a <strong>single-writer advisory lock</strong> so only one process migrates even if replicas start together.</li><li>A <strong><code>schema_migrations</code> ledger</strong> records applied versions; the app <strong>fails fast</strong> and refuses to serve if a migration errors (never serve a half-migrated DB).</li><li>Migrations cover the <strong>platform schema</strong>, the <strong>auth server&#39;s tables</strong> (alongside better-auth&#39;s own migrator), and <strong>per-plugin schemas</strong> (RFC 0004) under the same framework.</li><li>Bootstrap DDL (<code>bootstrapPlatformDb()</code>) is retained only for the <strong>first install</strong>; migrations own evolution thereafter. The schema-parity test remains the guard that both dialects stay in step.</li></ul><p><strong>Expand-contract (hard rule).</strong> Every release is <strong>backward-compatible</strong>: a schema change is introduced additively (<strong>expand</strong>), the new code deploys and backfills, and the old shape is removed only in a <strong>later</strong> release (<strong>contract</strong>) once no running version depends on it. This is what makes blue-green overlap safe and makes rollback to the previous image safe against the migrated database. Renames become add-new + dual-write + backfill + later drop; never a destructive in-place change within one release.</p><h3 id="_4-backups-restore-—-first-class-automatic-snapshot" tabindex="-1">4. Backups &amp; restore — first-class + automatic snapshot <a class="header-anchor" href="#_4-backups-restore-—-first-class-automatic-snapshot" aria-label="Permalink to &quot;4. Backups &amp; restore — first-class + automatic snapshot&quot;">​</a></h3><p><strong><code>sv backup</code> / <code>sv restore</code></strong> (in <code>bin/sv.ts</code>, pure helpers in <code>bin/helpers.ts</code>) — dialect-aware and covering the <strong>whole data surface</strong>:</p><ul><li>SQLite: a consistent file-level snapshot (<code>VACUUM INTO</code> / better-sqlite3 backup API) of <code>sovereign.db</code> + <code>auth.db</code>;</li><li>Postgres: <code>pg_dump</code> / <code>pg_restore</code>;</li><li>plus the <code>avatars/</code> directory and (future) per-plugin DBs/assets (RFC 0004).</li></ul><p>Snapshots are labeled (timestamp + platform version) so a restore targets a known-good point.</p><p><strong>Automatic pre-upgrade snapshot.</strong> The upgrade flow (the <code>migrate</code> step / an <code>sv upgrade</code> helper) takes a labeled snapshot <strong>before applying migrations</strong>. Retention is an operator-tunable count (keep the last <em>N</em>). This is the safety net that turns rollback from &quot;hope&quot; into a procedure.</p><h3 id="_5-versioning-compatibility-rollback" tabindex="-1">5. Versioning, compatibility &amp; rollback <a class="header-anchor" href="#_5-versioning-compatibility-rollback" aria-label="Permalink to &quot;5. Versioning, compatibility &amp; rollback&quot;">​</a></h3><ul><li><strong>Tag-pinned rollback.</strong> Because images are pinned by immutable patch tag and a pre-upgrade snapshot exists, rollback is: repin the previous <code>SOVEREIGN_VERSION</code>, <code>sv restore</code> the pre-upgrade snapshot, <code>up -d</code>. Safe by construction given expand-contract (the previous code never meets a schema it cannot read).</li><li><strong>Startup version gate.</strong> On boot, compare code version against the DB&#39;s recorded schema version: refuse to run <strong>code older than the DB</strong> (downgrade guard, unless paired with a matching restore) and require <strong>sequential</strong> major upgrades (no skipping a major). Surface the result in <code>/api/admin/health</code>.</li><li><strong>Plugin ↔ platform compatibility.</strong> Reuse the manifest <code>compatibility.minPlatformVersion</code> field as an install-/start-time check so a plugin built for a newer platform fails loudly rather than misbehaving.</li></ul><h3 id="_6-end-to-end-upgrade-flow" tabindex="-1">6. End-to-end upgrade flow <a class="header-anchor" href="#_6-end-to-end-upgrade-flow" aria-label="Permalink to &quot;6. End-to-end upgrade flow&quot;">​</a></h3><ol><li>Operator bumps <code>SOVEREIGN_VERSION</code> and <code>docker compose pull</code>.</li><li><code>up -d</code> starts the <code>migrate</code> step: <strong>auto pre-upgrade snapshot</strong> → acquire advisory lock → apply pending migrations → release lock (<strong>fail-fast</strong> on error, leaving the snapshot intact).</li><li>App services recreate; <strong>graceful shutdown</strong> drains the old containers while the reverse proxy retries onto the new ones.</li><li>Operator verifies <code>/api/admin/health</code> (version, DB, auth reachability).</li><li><strong>Rollback if needed:</strong> repin previous tag + <code>sv restore</code> + <code>up -d</code>.</li></ol><h2 id="impact-when-accepted" tabindex="-1">Impact when accepted <a class="header-anchor" href="#impact-when-accepted" aria-label="Permalink to &quot;Impact when accepted&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Where</th><th>Change</th></tr></thead><tbody><tr><td>CI (Task 0.5.8 dependency)</td><td>Build + push semver-tagged runtime/auth images to the registry.</td></tr><tr><td><code>Dockerfile</code>, <code>apps/auth/Dockerfile</code></td><td>Graceful-shutdown entrypoint handling; align <code>HEALTHCHECK</code>.</td></tr><tr><td>Compose files</td><td><code>image:</code> tags + <code>SOVEREIGN_VERSION</code>, a gated <code>migrate</code> step, <code>stop_grace_period</code>; blue-green example.</td></tr><tr><td><code>packages/db</code></td><td><code>drizzle.config</code>, <code>migrations/</code>, load-bearing <code>runMigrations</code>, advisory lock, <code>schema_migrations</code>, gate.</td></tr><tr><td><code>apps/auth</code></td><td>Graceful shutdown; align migration gating with the platform step.</td></tr><tr><td><code>bin/sv</code></td><td><code>backup</code>, <code>restore</code>, and an <code>upgrade</code> helper.</td></tr><tr><td><code>docs/self-hosting.md</code>, <code>docs/upgrade.md</code></td><td>Image-pull upgrade, tiered cutover + blue-green, backup/restore, rollback.</td></tr><tr><td>SRS §3.1 + NFRs</td><td>Promote to specified; new <code>DEP-xx</code> requirement IDs + decision-log entry.</td></tr><tr><td><code>docs/roadmap.md</code></td><td>Sequenced tasks (migrations foundation → graceful shutdown → backup/restore → image/CI → blue-green docs).</td></tr></tbody></table><h2 id="alternatives-considered" tabindex="-1">Alternatives considered <a class="header-anchor" href="#alternatives-considered" aria-label="Permalink to &quot;Alternatives considered&quot;">​</a></h2><ol><li><strong>Build-on-host only</strong> (status quo). No registry infrastructure, but downtime includes the build and rollback means git-revert + rebuild. Kept as a documented fallback, rejected as the canonical path.</li><li><strong>Multi-node rolling / orchestrator (Kubernetes, Swarm).</strong> True rolling updates, but conflicts with NFR-01 (single-machine Compose) and adds operational weight inappropriate for the self-hosted, single-tenant target. Out of scope.</li><li><strong>Keep idempotent bootstrap, no migrations.</strong> Cannot express renames/drops or guarantee rollback safety, and offers no applied-version ledger. Rejected.</li><li><strong>Docs-only backups</strong> (manual <code>pg_dump</code>/<code>tar</code>). Lower build cost but a weaker rollback guarantee and no pre-upgrade safety net. Rejected in favour of tooled <code>sv backup</code>/<code>restore</code> + automatic snapshot.</li><li><strong>Two replicas + Compose rolling.</strong> Compose has no clean rolling primitive for a single published port; blue-green behind the existing proxy is simpler and gives the same guarantee.</li></ol><h2 id="open-questions" tabindex="-1">Open questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open questions&quot;">​</a></h2><ol><li><strong>Registry &amp; signing.</strong> GHCR (proposed) vs Docker Hub; whether to sign images (cosign) and publish an SBOM.</li><li><strong>Migrate step shape.</strong> A dedicated one-shot <code>migrate</code> service gated by <code>depends_on</code> vs a startup hook inside each app. The one-shot service avoids races when both apps start together; the hook is simpler.</li><li><strong>SQLite consistency.</strong> <code>VACUUM INTO</code> / online backup vs a brief quiesce during snapshot — and whether the auto-snapshot blocks writes momentarily.</li><li><strong>Snapshot retention &amp; disk budget.</strong> Sensible default count, and behaviour when disk is constrained.</li><li><strong>Blue-green on one volume.</strong> How two stacks share the single named data volume safely (read/write expectations during overlap; avatar writes).</li><li><strong>Large Postgres DBs.</strong> Auto-snapshot time/size for big databases — make it skippable with an explicit operator opt-out + warning.</li></ol><h2 id="adoption-path" tabindex="-1">Adoption path <a class="header-anchor" href="#adoption-path" aria-label="Permalink to &quot;Adoption path&quot;">​</a></h2><ol><li><strong>Migrations foundation</strong> — drizzle-kit config + first generated migration + load-bearing runner + advisory lock + <code>schema_migrations</code>, keeping bootstrap for first install. Establish the expand-contract rule in CLAUDE.md.</li><li><strong>Graceful shutdown</strong> — SIGTERM draining in both servers + <code>stop_grace_period</code>.</li><li><strong>Backups</strong> — <code>sv backup</code>/<code>restore</code> + automatic pre-upgrade snapshot.</li><li><strong>Images &amp; CI</strong> — semver-tagged image publishing (with Task 0.5.8) + <code>image:</code>-based <code>docker-compose.prod.yml</code> + <code>SOVEREIGN_VERSION</code>.</li><li><strong>Docs</strong> — rewrite the upgrade procedure; add blue-green and rollback guides.</li><li><strong>SRS</strong> — add <code>DEP-xx</code> requirements + decision-log entry on acceptance.</li></ol><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Version</th><th>Date</th><th>Change</th></tr></thead><tbody><tr><td>0.1</td><td>Jun 2026</td><td>Initial draft.</td></tr><tr><td>1.0</td><td>Jun 2026</td><td>Accepted; incorporated into SRS §3.15 and Task 0.5.14.</td></tr></tbody></table>`,47)])])}const u=t(r,[["render",n]]);export{h as __pageData,u as default};
